// ════════════════════════════════════════════════════════
// Normalisation : unifie Telegram + Webhook en 1 payload commun
// FIX v13.3 : pour Telegram, on charge finance_data.json depuis le VPS
// (le trigger Telegram ne reçoit que du texte, pas de contexte budget).
// ════════════════════════════════════════════════════════
const item = $input.first();
const src = item.json;

let source, session_id, question, finance_data, chat_id;

if (src.message && src.message.chat) {
  // ── Telegram ──
  source = 'telegram';
  chat_id = String(src.message.chat.id);
  session_id = 'tg_' + chat_id;
  question = (src.message.text || '').trim();
  finance_data = null; // sera chargé via HTTP ci-dessous
} else if (src.body || src.question || src.session_id) {
  // ── Webhook Web ──
  const body = src.body || src;
  source = 'web';
  session_id = body.session_id || ('web_' + Date.now());
  chat_id = null;
  question = (body.question || '').trim();
  finance_data = body.finance_data || null;
} else {
  throw new Error('Payload inconnu : impossible de normaliser.');
}

if (!question) {
  throw new Error('Question vide.');
}

// ── FIX 1 : injection du finance_data pour Telegram ──
// Si source=telegram (ou si web n'a pas envoyé de payload), on récupère
// le fichier officiel depuis le VPS via l'endpoint GET de save_data.php.
if (!finance_data) {
  try {
    const fetched = await this.helpers.httpRequest({
      method: 'GET',
      url: 'https://n8n.beau.ink/finance/save_data.php',
      json: true,
      timeout: 10000
    });
    if (fetched && typeof fetched === 'object' && fetched.donneesAnnuelles) {
      finance_data = fetched;
    } else {
      // Endpoint a renvoyé {} ou structure invalide — on continue sans
      finance_data = null;
    }
  } catch (e) {
    // Échec de fetch : on continue sans, l'agent dira ce qu'il manque
    finance_data = null;
  }
}

return [{
  json: {
    source,
    session_id,
    chat_id,
    question,
    finance_data_json: finance_data ? JSON.stringify(finance_data) : null,
    finance_data,
    finance_data_loaded_from: finance_data ? (source === 'web' && src.body && src.body.finance_data ? 'webhook_payload' : (source === 'web' && src.finance_data ? 'webhook_payload' : 'vps_save_data_php')) : 'none'
  }
}];

// ════════════════════════════════════════════════════════
// BUILD AGENT INPUT — formate l'historique nettoyé en bloc texte
// et le combine avec la question + finance_data du Normalize Input.
// L'agent reçoit ainsi une conversation_history plate (zéro tool_call),
// donc Gemini ne peut jamais tomber sur une séquence function_call orpheline.
// ════════════════════════════════════════════════════════
const normalized = $('Normalize Input').first().json;

// Récupère les rows SELECT (Load Sane History)
let rows = [];
try {
  rows = $input.all().map(item => item.json).filter(r => r && r.msg_json);
} catch (e) {
  rows = [];
}

// SQL renvoie ORDER BY id DESC -> on remet en ordre chronologique
rows = rows.reverse();

// Formate en bloc texte lisible par le modèle
let history_text = '';
if (rows.length > 0) {
  const lines = [];
  for (const row of rows) {
    let parsed;
    try { parsed = typeof row.msg_json === 'string' ? JSON.parse(row.msg_json) : row.msg_json; }
    catch (e) { continue; }
    const type = parsed.type;
    const content = (parsed.data && parsed.data.content) || '';
    if (!content || typeof content !== 'string') continue;
    // Strip HTML tags pour réduire la longueur du contexte
    const plain = content
      .replace(/<br\s*\/?>/gi, ' ')
      .replace(/<\/?[^>]+(>|$)/g, '')
      .replace(/\s+/g, ' ')
      .trim();
    if (!plain) continue;
    const tag = type === 'human' ? 'User' : 'Assistant';
    // Tronque chaque message à 600 chars pour limiter le contexte
    const truncated = plain.length > 600 ? plain.slice(0, 600) + '…' : plain;
    lines.push(`[${tag}]: ${truncated}`);
  }
  if (lines.length > 0) {
    history_text = 'HISTORIQUE RÉCENT (derniers échanges, texte brut sans tool calls) :\n' + lines.join('\n') + '\n';
  }
}

return [{
  json: {
    source: normalized.source,
    session_id: normalized.session_id,
    chat_id: normalized.chat_id,
    question: normalized.question,
    finance_data_json: normalized.finance_data_json,
    finance_data: normalized.finance_data,
    finance_data_loaded_from: normalized.finance_data_loaded_from,
    history_text,
    history_count: rows.length
  }
}];

